import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../../store/slices/authSlice';

const NAV = [
  { to: '/', label: 'Dashboard', icon: '🏠' },
  { to: '/students', label: 'Students', icon: '👨‍🎓' },
  { to: '/attendance', label: 'Attendance', icon: '✅' },
  { to: '/fees', label: 'Fee Management', icon: '💰' },
  { to: '/employees', label: 'Employees', icon: '👥' },
  { to: '/reports', label: 'Reports', icon: '📈' },
];

export default function Layout() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector(s => s.auth.user);
  const handleLogout = async () => { await dispatch(logout()); navigate('/login'); };

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      <aside style={{ width: 230, background: '#2D1B69', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
        <div style={{ padding: '16px', borderBottom: '1px solid rgba(255,255,255,.1)', display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{ width: 32, height: 32, background: 'linear-gradient(135deg,#A78BFA,#F59E0B)', borderRadius: 9, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16 }}>🏫</div>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, color: '#fff' }}>EduManage</div>
            <div style={{ fontSize: 10, color: 'rgba(255,255,255,.4)', textTransform: 'uppercase', letterSpacing: '.08em' }}>School ERP</div>
          </div>
        </div>
        <div style={{ padding: '10px 14px', borderBottom: '1px solid rgba(255,255,255,.1)', display: 'flex', alignItems: 'center', gap: 9 }}>
          <div style={{ width: 28, height: 28, borderRadius: 7, background: 'linear-gradient(135deg,#A78BFA,#F59E0B)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700, color: '#fff' }}>
            {user?.full_name?.[0] || 'U'}
          </div>
          <div>
            <div style={{ fontSize: 12, fontWeight: 600, color: '#fff' }}>{user?.full_name || 'User'}</div>
            <div style={{ fontSize: 10, color: 'rgba(255,255,255,.4)', textTransform: 'capitalize' }}>{user?.role}</div>
          </div>
        </div>
        <nav style={{ flex: 1, overflowY: 'auto', padding: '8px 0' }}>
          {NAV.map(n => (
            <NavLink key={n.to} to={n.to} end={n.to === '/'}
              style={({ isActive }) => ({
                display: 'flex', alignItems: 'center', gap: 9, padding: '8px 16px',
                color: isActive ? '#fff' : 'rgba(255,255,255,.55)',
                fontSize: 12, fontWeight: isActive ? 600 : 400,
                borderLeft: `2px solid ${isActive ? '#A78BFA' : 'transparent'}`,
                background: isActive ? 'rgba(255,255,255,.12)' : 'transparent',
                textDecoration: 'none', transition: 'all .12s'
              })}>
              <span style={{ fontSize: 14, width: 16, textAlign: 'center' }}>{n.icon}</span>
              {n.label}
            </NavLink>
          ))}
        </nav>
        <div style={{ padding: '12px 16px', borderTop: '1px solid rgba(255,255,255,.1)' }}>
          <button onClick={handleLogout} style={{ width: '100%', padding: '8px', border: '1px solid rgba(255,255,255,.2)', borderRadius: 8, background: 'transparent', color: 'rgba(255,255,255,.6)', fontSize: 12, cursor: 'pointer' }}>
            Logout
          </button>
        </div>
      </aside>
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <header style={{ height: 52, background: '#fff', borderBottom: '0.5px solid #E5E7EB', display: 'flex', alignItems: 'center', padding: '0 20px', gap: 12, flexShrink: 0 }}>
          <div style={{ flex: 1 }} />
          <input placeholder="🔍 Search…" style={{ padding: '6px 12px', border: '1px solid #E5E7EB', borderRadius: 8, fontSize: 12, width: 240, outline: 'none' }} />
          <div style={{ fontSize: 13, fontWeight: 600, color: '#374151' }}>{user?.school_name || 'School'}</div>
        </header>
        <div style={{ flex: 1, overflowY: 'auto', padding: 20 }}>
          <Outlet />
        </div>
      </main>
    </div>
  );
}
